const Hello = (props) => {
  console.log(props)
  return (
    <div>
      <p>Hello {props.name}, you are {props.age} years old and you were born in {props.birthplace}</p>
    </div>
  )
}

const App = () => {
  const name = 'Peter'
  const age = 10
  const birthplace = 'Helsinki'

  return (
    <div>
      <h1>Greetings</h1>
      <Hello name='Maya' age={26 + 10} birthplace='Turku'/>
      <Hello name={name} age={age} birthplace={birthplace}/>
    </div>
  )
}

export default App
